import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Play, Pause, Download, Loader2, CheckCircle, XCircle, List, TerminalSquare, RotateCcw, BoxSelect } from 'lucide-react';
import { BatchStatus } from '../types';
import { fetchJson, API_BASE } from '../src/lib/http';

export default function BatchExtract() {
  const [urls, setUrls] = useState('');
  const [status, setStatus] = useState<BatchStatus>({ queue: [], isProcessing: false, completedCount: 0, failedCount: 0, totalCount: 0 });
  const [format, setFormat] = useState<'talevox' | 'generic'>('talevox');
  const [isDownloading, setIsDownloading] = useState(false);

  useEffect(() => {
    fetchStatus();
    const interval = setInterval(fetchStatus, 1000);
    return () => clearInterval(interval);
  }, []);

  const fetchStatus = async () => {
      try {
          const data = await fetchJson<BatchStatus>('/api/batch/status');
          setStatus(data);
      } catch (e) { console.error(e); }
  };

  const addToQueue = async () => {
    const list = urls.split('\n').map(u => u.trim()).filter(u => u);
    if (!list.length) return;
    await fetchJson('/api/batch/add', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ urls: list })
    });
    setUrls('');
    fetchStatus();
  };

  const toggleProcessing = async () => {
      const endpoint = status.isProcessing ? '/api/batch/stop' : '/api/batch/start';
      await fetchJson(endpoint, { method: 'POST' });
      fetchStatus();
  };

  const retryFailed = async () => {
      await fetchJson('/api/batch/retry', { method: 'POST' });
      fetchStatus();
  };

  const clear = async () => {
      await fetchJson('/api/batch/clear', { method: 'POST' });
      fetchStatus();
  };

  const download = async () => {
      setIsDownloading(true);
      try {
          const filename = `ronin_batch_${format}.zip`;

          // 1. Fetch the Blob
          // Removed fileType param, backend now handles auto-detection per file
          const response = await fetch(`${API_BASE}/api/batch/download?format=${format}`);
          if (!response.ok) throw new Error('Network response was not ok');
          const blob = await response.blob();

          // 2. Try modern "Save As" (File System Access API)
          if ('showSaveFilePicker' in window) {
              try {
                  const opts = {
                      suggestedName: filename,
                      types: [{
                          description: 'ZIP Archive',
                          accept: { 'application/zip': ['.zip'] },
                      }],
                  };
                  // @ts-ignore
                  const handle = await window.showSaveFilePicker(opts);
                  const writable = await handle.createWritable();
                  await writable.write(blob);
                  await writable.close();
                  return; // Success
              } catch (err: any) {
                  if (err.name === 'AbortError') return;
              }
          }

          // 3. Fallback: Standard Download Link
          const url = window.URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.style.display = 'none';
          a.href = url;
          a.download = filename;
          document.body.appendChild(a);
          a.click();

          setTimeout(() => {
              window.URL.revokeObjectURL(url);
              document.body.removeChild(a);
          }, 100);

      } catch (e) {
          console.error('Download failed', e);
          alert("Failed to download archive. See console for details.");
      } finally {
          setIsDownloading(false);
      }
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-end border-b border-white/10 pb-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
             <List className="text-katana" /> Batch Processor
          </h2>
          <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; AWAITING INPUT STREAM</p>
        </div>
        <div className="flex gap-3 items-center">
           {!status.isProcessing && status.failedCount > 0 && (
               <button onClick={retryFailed} className="border border-red-500/50 text-red-400 hover:bg-red-500/10 px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all">
                   <RotateCcw className="w-4 h-4" /> Retry Failures
               </button>
           )}

           {/* Controls Container */}
           <div className="flex gap-2 mr-2">
                {/* Format Toggle */}
                <div className="flex items-center border border-white/10 rounded overflow-hidden">
                        <button 
                            onClick={() => setFormat('talevox')} 
                            className={`px-3 py-2 text-[10px] font-bold uppercase tracking-wider transition-colors ${format === 'talevox' ? 'bg-katana text-black' : 'bg-void text-steel hover:text-white'}`}
                        >
                            TaleVox
                        </button>
                        <div className="w-px h-full bg-white/10"></div>
                        <button 
                            onClick={() => setFormat('generic')} 
                            className={`px-3 py-2 text-[10px] font-bold uppercase tracking-wider transition-colors ${format === 'generic' ? 'bg-katana text-black' : 'bg-void text-steel hover:text-white'}`}
                        >
                            Generic
                        </button>
                </div>
           </div>

           <button onClick={toggleProcessing} disabled={status.queue.length === 0} className={`px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all border ${status.isProcessing ? 'border-yellow-500 text-yellow-500 hover:bg-yellow-500/10' : 'bg-katana text-black border-katana hover:bg-red-600'}`}>
               {status.isProcessing ? <><Pause className="w-4 h-4" /> Pause</> : <><Play className="w-4 h-4 fill-current" /> Engage</>}
           </button>
           <button onClick={download} disabled={status.completedCount === 0 || isDownloading} className="border border-white/20 text-white hover:border-katana hover:text-katana px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30">
             {isDownloading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
             Archive
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        <div className="bg-armor border border-white/10 p-1 flex flex-col h-full">
           <textarea
            className="flex-1 w-full p-4 bg-void text-steel focus:outline-none focus:bg-black font-mono text-xs resize-none placeholder:text-gray-800"
            placeholder="PASTE URLS [ONE PER LINE]..."
            value={urls}
            onChange={e => setUrls(e.target.value)}
          />
          <button onClick={addToQueue} className="w-full bg-white/5 text-white py-3 hover:bg-katana hover:text-black border-t border-white/10 font-mono text-xs uppercase tracking-widest flex justify-center items-center gap-2 transition-colors">
            <Plus className="w-4 h-4" /> Add to Queue
          </button>
        </div>

        <div className="lg:col-span-2 bg-armor border border-white/10 flex flex-col min-h-0">
           <div className="p-3 bg-white/5 border-b border-white/5 flex justify-between items-center">
               <div className="flex gap-4 font-mono text-xs">
                   <span className="text-steel">TOTAL: <span className="text-white">{status.totalCount}</span></span>
                   <span className="text-steel">OK: <span className="text-green-500">{status.completedCount}</span></span>
                   <span className="text-steel">FAIL: <span className="text-katana">{status.failedCount}</span></span>
               </div>
               <button onClick={clear} className="text-steel hover:text-katana"><Trash2 className="w-4 h-4"/></button>
           </div>

           <div className="flex-1 overflow-y-auto custom-scrollbar">
               <table className="w-full text-left font-mono text-xs">
                   <thead className="text-steel bg-black/20 sticky top-0">
                       <tr>
                           <th className="px-4 py-2">State</th>
                           <th className="px-4 py-2">Payload</th>
                       </tr>
                   </thead>
                   <tbody className="divide-y divide-white/5">
                       {status.queue.map(item => (
                           <tr key={item.id} className="hover:bg-white/5">
                               <td className="px-4 py-2 w-32">
                                   {item.status === 'pending' && <span className="text-steel">WAITING</span>}
                                   {item.status === 'processing' && <span className="text-blue-400 flex gap-2 items-center"><Loader2 className="w-3 h-3 animate-spin"/> RUNNING</span>}
                                   {item.status === 'success' && <span className="text-green-500 flex gap-2 items-center"><CheckCircle className="w-3 h-3"/> OK</span>}
                                   {item.status === 'failed' && <span className="text-katana flex gap-2 items-center"><XCircle className="w-3 h-3"/> FAIL</span>}
                               </td>
                               <td className="px-4 py-2 truncate max-w-xs">
                                   <div className="text-white truncate">{item.result?.title || item.url}</div>
                                   {item.error && <div className="text-red-500">{item.error}</div>}
                               </td>
                           </tr>
                       ))}
                   </tbody>
               </table>
               {status.queue.length === 0 && (
                   <div className="flex flex-col items-center justify-center h-full opacity-20 gap-4">
                       <TerminalSquare className="w-12 h-12"/>
                       <span className="font-mono text-xs tracking-widest">BUFFER EMPTY</span>
                   </div>
               )}
           </div>
        </div>
      </div>
    </div>
  );
}

import express from 'express';
import cors from 'cors';
import * as storage from './storage.ts';
import * as extractor from './extractor.ts';
import * as queue from './queue.ts';
import { normalizeHost } from './domain.ts';

const app = express();
const PORT = process.env.PORT || 8787;

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Init
storage.initStorage().catch(console.error);

// Async Wrapper
const asyncHandler = (fn: any) => (req: any, res: any, next: any) => {
    Promise.resolve(fn(req, res, next)).catch(next);
};

// --- ROUTES ---

app.get('/api/health', (req, res) => res.json({ status: 'ok', version: '2.0.0' }));

// Settings
app.get('/api/settings', asyncHandler(async (req: any, res: any) => {
    res.json(await storage.getSettings());
}));

app.post('/api/settings', asyncHandler(async (req: any, res: any) => {
    await storage.saveSettings(req.body);
    res.json({ success: true });
}));

// Templates
app.get('/api/templates', asyncHandler(async (req: any, res: any) => {
    res.json(await storage.getTemplates());
}));

// Get list of defaults (Library)
app.get('/api/templates/defaults', (req, res) => {
    res.json(storage.getDefaultTemplates());
});

// Force seed defaults (legacy/maintenance)
app.post('/api/templates/defaults', asyncHandler(async (req: any, res: any) => {
    await storage.seedDefaults();
    res.json(await storage.getTemplates());
}));

app.post('/api/templates', asyncHandler(async (req: any, res: any) => {
    const input = req.body;
    const templates = await storage.getTemplates();

    const now = Date.now();
    const doc = {
        id: input.id || Math.random().toString(36).substring(2, 9),
        domain: normalizeHost(input.domain),
        titleSelector: input.titleSelector,
        contentSelector: input.contentSelector,
        removeSelectors: input.removeSelectors || [],
        cookies: input.cookies,
        userAgent: input.userAgent,
        createdAt: input.createdAt || now,
        updatedAt: now
    };

    const idx = templates.findIndex(t => t.id === doc.id);
    if (idx >= 0) templates[idx] = doc;
    else templates.push(doc);

    await storage.saveTemplates(templates);
    res.json({ success: true, doc });
}));

app.delete('/api/templates/:id', asyncHandler(async (req: any, res: any) => {
    let templates = await storage.getTemplates();
    templates = templates.filter(t => t.id !== req.params.id);
    await storage.saveTemplates(templates);
    res.json({ success: true });
}));

// Extraction
app.post('/api/extract', asyncHandler(async (req: any, res: any) => {
    const { url } = req.body;
    if (!url) throw new Error("URL required");
    const templates = await storage.getTemplates();
    const result = await extractor.extract(url, templates);
    res.json({ success: true, data: result });
}));

app.post('/api/protocol/diagnostics', asyncHandler(async (req: any, res: any) => {
    const { url, domain, titleSelector, contentSelector, removeSelectors, cookies, userAgent } = req.body;
    const result = await extractor.runDiagnostics(url, domain, titleSelector, contentSelector, removeSelectors, cookies, userAgent);
    res.json(result);
}));

// Batch
app.get('/api/batch/status', (req, res) => {
    res.json(queue.getStatus());
});

app.post('/api/batch/add', (req, res) => {
    const { urls } = req.body; // Expect array of strings
    if (Array.isArray(urls)) {
        queue.addItems(urls);
    }
    res.json({ success: true });
});

app.post('/api/batch/start', asyncHandler(async (req: any, res: any) => {
    queue.startProcessing();
    res.json({ success: true });
}));

app.post('/api/batch/stop', (req, res) => {
    queue.stopProcessing();
    res.json({ success: true });
});

app.post('/api/batch/retry', (req, res) => {
    queue.retryFailed();
    res.json({ success: true });
});

app.post('/api/batch/clear', (req, res) => {
    queue.clearQueue();
    res.json({ success: true });
});

app.get('/api/batch/download', asyncHandler(async (req: any, res: any) => {
    const format = req.query.format as string || 'talevox';
    const buffer = await queue.createBatchZip(format);
    res.set('Content-Type', 'application/zip');
    res.set('Content-Disposition', `attachment; filename=ronin_batch_${format}.zip`);
    res.send(buffer);
}));

// Error Handler
app.use((err: any, req: any, res: any, next: any) => {
    console.error(err);
    res.status(500).json({ error: err.message });
});

app.listen(PORT, () => {
    console.log(`RoninClip Backend running on port ${PORT}`);
});

import type { BatchItem, BatchStatus } from '../types.ts';
import * as extractor from './extractor.ts';
import * as storage from './storage.ts';
import * as talevox from './exporters/talevoxExporter.ts';
import { normalizeHost } from './domain.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';
import { Buffer } from 'buffer';

let queue: BatchItem[] = [];
let isProcessing = false;
let activeWorkers = 0;
let shouldStop = false;

// Token bucket for rate limiting
let tokens = 0;
let lastRefill = Date.now();

export function getStatus(): BatchStatus {
    const completed = queue.filter(i => i.status === 'success').length;
    const failed = queue.filter(i => i.status === 'failed').length;
    return {
        queue,
        isProcessing,
        completedCount: completed,
        failedCount: failed,
        totalCount: queue.length
    };
}

export function addItems(urls: string[]) {
    const newItems = urls.map(url => ({
        id: Math.random().toString(36).substring(2, 9),
        url: url.trim(),
        status: 'pending' as const
    }));
    queue.push(...newItems);
}

export function clearQueue() {
    if (!isProcessing) {
        queue = [];
    }
}

export function retryFailed() {
    if (isProcessing) return;
    queue.forEach(item => {
        if (item.status === 'failed') {
            item.status = 'pending';
            item.error = undefined;
            item.result = undefined;
        }
    });
}

export async function startProcessing() {
    if (isProcessing) return;
    shouldStop = false;
    isProcessing = true;

    const settings = await storage.getSettings();
    const maxConcurrency = settings.concurrency || 1;

    // Init tokens
    tokens = settings.rateLimitPerMinute; 
    lastRefill = Date.now();

    // Main loop
    while (!shouldStop) {
        // Refill tokens
        const now = Date.now();
        const elapsed = now - lastRefill;
        if (elapsed > 60000) {
            tokens = settings.rateLimitPerMinute;
            lastRefill = now;
        }

        // Check completion
        const pending = queue.find(i => i.status === 'pending');
        if (!pending && activeWorkers === 0) {
            isProcessing = false;
            break;
        }

        // Spawn worker if allowed
        if (pending && activeWorkers < maxConcurrency && tokens > 0) {
            tokens--;
            activeWorkers++;

            // Add a random jitter delay (500ms - 2500ms) to simulate human behavior
            await new Promise(r => setTimeout(r, Math.random() * 2000 + 500));

            processItem(pending).finally(() => {
                activeWorkers--;
            });
        }

        // Wait a bit before next loop tick
        await new Promise(r => setTimeout(r, 200));
    }

    isProcessing = false;
}

export function stopProcessing() {
    shouldStop = true;
}

async function processItem(item: BatchItem) {
    item.status = 'processing';
    try {
        const templates = await storage.getTemplates();
        const result = await extractor.extract(item.url, templates);
        item.result = result;
        item.status = 'success';
    } catch (e: any) {
        item.status = 'failed';
        item.error = e.message;
        console.error(`Failed ${item.url}:`, e);
    }
}

export async function createBatchZip(format: string = 'talevox') {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    if (format === 'talevox') {
        // TaleVox Export Logic

        // 1. Determine Series Slug (Heuristic: Use domain of first item or 'series')
        let seriesSlug = 'series';
        if (successItems.length > 0) {
            const host = normalizeHost(successItems[0].url);
            seriesSlug = host.replace(/\./g, '_');
        }

        const manifestItems: Array<{index: number, title: string, filename: string, url: string}> = [];
        const usedFilenames = new Set<string>();

        successItems.forEach((item, idx) => {
            if (!item.result) return;

            // Auto-detect extension based on rich content detection (tables, etc.)
            const ext = item.result.hasRichContent ? '.md' : '.txt';

            const index = idx + 1; // 1-based index based on queue order
            // Ensure filename has correct extension
            let filename = talevox.buildFilename(seriesSlug, index, item.result.title).replace('.txt', ext);

            // Handle duplicates
            let version = 2;
            while(usedFilenames.has(filename)) {
                filename = filename.replace(ext, `__v${version}${ext}`);
                version++;
            }
            usedFilenames.add(filename);

            // Note: formatChapterContent does standard spacing. 
            // Markdown syntax inside content (like ASCII boxes or MD tables) remains valid text.
            const content = talevox.formatChapterContent(index, item.result.title, item.result.content);

            zip.addFile(filename, Buffer.from(content, 'utf8'));

            manifestItems.push({
                index,
                title: item.result.title,
                filename,
                url: item.url
            });
        });

        const manifestJson = talevox.generateManifest(seriesSlug, manifestItems);
        zip.addFile('talevox_manifest.json', Buffer.from(manifestJson, 'utf8'));

    } else {
        // Generic Export Logic
        successItems.forEach(item => {
            if (item.result) {
                // Auto-detect extension
                const ext = item.result.hasRichContent ? '.md' : '.txt';

                const safeTitle = sanitize(item.result.title).substring(0, 100);
                const content = `${item.result.title}\n\n${item.result.content}`;
                zip.addFile(`${safeTitle}${ext}`, Buffer.from(content, 'utf8'));
            }
        });

        // Add generic manifest
        const manifest = {
            generatedAt: new Date().toISOString(),
            total: successItems.length,
            items: successItems.map(i => {
                const ext = i.result?.hasRichContent ? '.md' : '.txt';
                return {
                    url: i.url,
                    title: i.result?.title,
                    filename: `${sanitize(i.result?.title || '')}${ext}`
                };
            })
        };
        zip.addFile('manifest.json', Buffer.from(JSON.stringify(manifest, null, 2), 'utf8'));
    }

    return zip.toBuffer();
}

