  contentPreview: string;
  error?: string;
}

export interface BatchItem {
  id: string;
  url: string;
  status: 'pending' | 'processing' | 'success' | 'failed';
  result?: ExtractedChapter;
  error?: string;
  // Manual overrides for TaleVox
  manualSeriesTitle?: string;
