/**
 * Checks if HTML string contains the required selector.
 * If not, checks for common anti-bot signatures.
 */
function validateHtml(html: string, waitForSelector?: string): boolean {
    if (!waitForSelector) return true;

    const $ = cheerio.load(html);
    const selectors = waitForSelector.split(',').map(s => s.trim());
    let found = false;
    for (const s of selectors) {
        if ($(s).length > 0) {
            found = true;
            break;
        }
    }

    if (!found) {
        if (html.includes('Just a moment') || html.includes('Enable JavaScript') || html.includes('Verify you are human') || html.includes('Performing security verification')) {
            throw new Error("Cloudflare/Bot challenge detected (Page blocked)");
        }
        throw new Error(`Selector '${waitForSelector}' not found in response`);
    }
    return true;
}

async function fetchPlaywright(url: string, headless: boolean, waitForSelector?: string, cookies?: string, userAgent?: string): Promise<string> {
    const ua = userAgent || DEFAULT_USER_AGENT;

    // ARGS for stealth
    // Important: --disable-blink-features=AutomationControlled is key for Cloudflare
    const args = [
        '--disable-blink-features=AutomationControlled',
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-infobars',
        '--window-position=0,0',
        '--disable-extensions',
    ];

    let browser = null;
    let context = null;
    let page = null;

    try {
        // --- CONTEXT CREATION STRATEGY ---
        if (headless) {
             // Tier 2: Ephemeral, Headless, Fast
             browser = await chromium.launch({ headless: true, args, ignoreDefaultArgs: ['--enable-automation'] });
             const domain = new URL(url).origin;
             context = await browser.newContext({
                userAgent: ua,
                viewport: { width: 1920, height: 1080 },
                locale: 'en-US',
                deviceScaleFactor: 1,
                timezoneId: 'America/New_York',
                javaScriptEnabled: true,
                extraHTTPHeaders: { 'Referer': domain, 'Origin': domain }
             });
        } else {
             // Tier 3: PERSISTENT PROFILE, Headful (The "Real User" Mode)
             // This stores cookies/localstorage in `data/browser_session_v3`.
             console.log(`[Tier 3] Launching Persistent Context at: ${USER_DATA_DIR}`);

             // NATIVE IDENTITY: 
             // We do NOT set the User Agent here unless the user specifically overrides it.
             // This allows Playwright to use the native browser version headers, preventing mismatches.
             const launchOptions: any = {
                headless: false,
                args,
                viewport: null, // Use actual window size
                ignoreDefaultArgs: ['--enable-automation'], // Hide "Chrome is being controlled by test software"
                locale: 'en-US',
             };

             // Only apply specific UA if it differs from the default string.
             // If user passes nothing (or default), we let the browser be itself.
             if (userAgent && userAgent !== DEFAULT_USER_AGENT) {
                 launchOptions.userAgent = userAgent;
             }

             context = await chromium.launchPersistentContext(USER_DATA_DIR, launchOptions);
        }

        // --- APPLY STEALTH INJECTION ---
        // This is crucial. It runs before the page loads.
        await context.addInitScript(STEALTH_INJECTION);

        if (cookies) {
            const cookieList = parseCookies(url, cookies);
            if (cookieList.length > 0) await context.addCookies(cookieList);
        }

        // Get page
        page = headless ? await context.newPage() : (context.pages()[0] || await context.newPage());

        if (headless) {
            // Speed optimization for headless
            await page.route('**/*.{png,jpg,jpeg,gif,webp,svg,woff,woff2}', route => route.abort());
        }

        // Navigate
        // Increased timeout to 90s to allow for manual user interaction if needed
        await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 90000 });

        // --- HUMAN BEHAVIOR SIMULATION (Headful Only) ---
        // Helps trigger "passive" turnstile checks
        if (!headless) {
            try {
                // Jiggle mouse
                await page.mouse.move(100, 100);
                await page.waitForTimeout(200);
                await page.mouse.move(200, 200, { steps: 10 });
                // Small scroll
                await page.mouse.wheel(0, 100);
            } catch (e) {}
        }

        // Wait for Content
        if (waitForSelector) {
            try {
                // Tier 2 gets 30s. Tier 3 gets 60s to allow user to solve captcha.
                const timeout = headless ? 30000 : 60000;
                await page.waitForSelector(waitForSelector, { state: 'attached', timeout });
                await page.waitForTimeout(1000); // Hydration wait
            } catch (e) {
                if (headless) throw new Error(`Timeout waiting for selector: ${waitForSelector}`);
                console.warn(`Headful timeout for ${waitForSelector}, grabbing current content anyway.`);
            }
        } else {
             await page.waitForTimeout(2000);
        }

        const content = await page.content();

        // Cleanup logic differs
        if (headless && browser) await browser.close();
        if (!headless && context) await context.close(); 

        return content;
    } catch (e: any) {
        // Ensure cleanup on error
        if (headless && browser) await browser.close();
        if (!headless && context) await context.close();
        throw e;
    }
}

/**
 * Unified fetch function with retry strategy (Tier 2 -> Tier 3 fallback)
 */
async function fetchHtml(url: string, waitForSelector?: string, cookies?: string, userAgent?: string): Promise<string> {
    try {
        // Attempt headless first (Tier 2)
        return await fetchPlaywright(url, true, waitForSelector, cookies, userAgent);
    } catch (e: any) {
        console.warn(`Headless fetch failed for ${url}: ${e.message}. Retrying with headful (Tier 3)...`);
        // Retry with headful (Tier 3) if headless fails
        try {
            return await fetchPlaywright(url, false, waitForSelector, cookies, userAgent);
        } catch (e2: any) {
            throw new Error(`Failed to fetch ${url}. \nHeadless: ${e.message}\nHeadful: ${e2.message}`);
        }
    }
}

export function findProtocol(url: string, templates: ProtocolTemplate[]): ProtocolTemplate | undefined {
    const host = normalizeHost(url);
    return templates.find(t => {
        const tHost = normalizeHost(t.domain);
        return host === tHost || host.endsWith('.' + tHost);
    });
}

export async function extract(url: string, templates: ProtocolTemplate[]) {
    const protocol = findProtocol(url, templates);
    const html = await fetchHtml(
        url, 
        protocol ? protocol.contentSelector : undefined, 
        protocol?.cookies,
        protocol?.userAgent
    );

    const $ = cheerio.load(html);

    let title = '';
    let body = '';
    let hasRichContent = false;

    if (protocol) {
        let $root = null;
        try {
            const selectors = protocol.contentSelector.split(',').map(s => s.trim());
            for (const s of selectors) {
                const found = $(s).first();
                if (found.length > 0) {
                    $root = found;
                    break; 
                }
            }
        } catch (e) {
            throw new Error(`Invalid content selector: ${protocol.contentSelector}`);
        }

        if (!$root || $root.length === 0) {
            throw new Error(`Content selector '${protocol.contentSelector}' matched 0 elements.`);
        }

        $('script, style, iframe, noscript, svg, form').remove(); 
        $('div[id^="pf-"]').remove(); 
        $('[style*="display: none"]').remove();
        $('[style*="display:none"]').remove();
        $('[aria-hidden="true"]').remove();
        $('[hidden]').remove();
        $('.hidden').remove();

        if (protocol.removeSelectors) {
             protocol.removeSelectors.forEach(sel => {
                 try {
                     if (sel && sel.trim()) $(sel).remove();
                 } catch (e) {
                     console.warn(`Skipping invalid remove selector: ${sel}`);
                 }
             });
        }

        try {
            const $title = $(protocol.titleSelector).first();
            title = cleanText($title.text());
        } catch (e) {
            console.warn(`Invalid title selector: ${protocol.titleSelector}`);
        }

        const paras: string[] = [];
        $root.find('br').replaceWith(` ${BR_TOKEN} `); 

        const blockTags = [
            'p', 'div', 'blockquote', 'pre', 
            'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 
            'li', 'article', 'section',
            'table'
        ];
        const selector = blockTags.join(', ');

        $root.find(selector).each((_, el) => {
            const $el = $(el);
            const tagName = el.tagName.toLowerCase();

            if (tagName === 'table') {
                 if ($el.parents('table').length > 0) return;

                 const rows: string[][] = [];
                 const headers: string[] = [];

                 $el.find('th').each((_, th) => {
                     headers.push(cleanText($(th).text()));
                 });

                 $el.find('tr').each((_, tr) => {
                     const cells: string[] = [];
                     const $tr = $(tr);
                     if ($tr.find('th').length > 0 && $tr.find('td').length === 0) return;

                     $tr.find('td').each((_, td) => {
                         const $td = $(td);
                         $td.find('p, div, li, h1, h2, h3, h4, h5').after(BR_TOKEN);
                         cells.push(cleanText($td.text()));
                     });
                     if (cells.length > 0) rows.push(cells);
                 });

                 // CHANGED: Removed special handling for single cells (ASCII art).
                 // Everything is now a markdown table.
                 paras.push(createMarkdownTable(headers, rows));
                 hasRichContent = true;
                 return;
            }

            if (tagName === 'blockquote') {
                if ($el.parents('table').length > 0) return;
                const qText = cleanText($el.text());
                paras.push(`> ${qText}`);
                hasRichContent = true;
                return;
            }

            if ($el.parents('table').length > 0) return;
            if ($el.find(selector).length > 0) return;

            const t = cleanText($el.text());
            if (t) paras.push(t);
        });

        // Pipeline: Clean Header -> Clean Footer
        // Deduplicate DISABLED
        const cleanedParas = cleanupHeader(paras, title);
        const fullyCleanedParas = cleanupFooter(cleanedParas, title);

        if (fullyCleanedParas.length === 0) {
            const raw = cleanText($root.text());
            if (raw.startsWith(title)) {
                body = raw.substring(title.length).trim();
            } else {
                body = raw;
            }
        } else {
            body = fullyCleanedParas.join('\n\n');
        }

    } else {
        $('script, style, iframe, noscript').remove();
        $('br').replaceWith(` ${BR_TOKEN} `);

        const titleEl = $('h1').first();
        title = cleanText(titleEl.text());

        const paras: string[] = [];
        $('p, div, blockquote, td, li').each((_, el) => {
             const $el = $(el);
             if ($el.find('p, div, blockquote, td, li').length > 0) return;
             const t = cleanText($el.text());
             if (t && t.length > 10) paras.push(t);
        });
        body = paras.join('\n\n');
        if (!body) throw new Error("No protocol found and auto-extraction failed.");
    }

    return {
        title,
        content: postProcessBody(body),
        url,
        matchedProtocol: protocol?.domain,
        hasRichContent
    };
}

export async function runDiagnostics(
    url: string, 
    domain: string, 
    titleSelector: string, 
    contentSelector: string, 
    removalSelectors: string[] = [],
    cookies?: string,
    userAgent?: string
): Promise<DiagnosticResult> {

    const html = await fetchHtml(url, contentSelector, cookies, userAgent);
    const $ = cheerio.load(html);
    const host = normalizeHost(url);

    $('script, style, iframe, noscript').remove();
    $('div[id^="pf-"]').remove();
    $('br').replaceWith(` ${BR_TOKEN} `);

    removalSelectors.forEach(s => { try { if(s.trim()) $(s).remove(); } catch (e) {} });

    let contentMatches = 0;
    let titleMatches = 0;
    let titleText = '';
    let pCount = 0;
    const paras: string[] = [];

    try {
        const $root = $(contentSelector).first();
        contentMatches = $root.length;

        if (contentMatches > 0) {
            const blockTags = ['p', 'div', 'blockquote', 'h1', 'h2', 'li', 'table'];
            const selector = blockTags.join(', ');

            $root.find(selector).each((_, el) => {
                const $el = $(el);

                if (el.tagName.toLowerCase() === 'table') {
                    if ($el.parents('table').length > 0) return;
                    paras.push("[TABLE/BOX DETECTED]");
                    pCount++;
                    return;
                }

                if ($el.find(selector).length > 0) return;
                if ($el.parents('table').length > 0) return;

                const t = cleanText($el.text());
                if (t) {
                    paras.push(t);
                    pCount++;
                }
            });
        }
    } catch (e) {
        return { host, titleMatches: 0, contentMatches: 0, paragraphCount: 0, titlePreview: '', contentPreview: '', error: `Invalid Content Selector` };
    }

    try {
        const $title = $(titleSelector).first();
        titleMatches = $title.length;
        titleText = cleanText($title.text());
    } catch (e) {
         return { host, titleMatches: 0, contentMatches, paragraphCount: 0, titlePreview: '', contentPreview: '', error: `Invalid Title Selector` };
    }

    let bodyPreview = '';
    if (paras.length > 0) {
        if (paras[0] === titleText) paras.shift();
        bodyPreview = paras.join('\n\n');
    } else {
        try { bodyPreview = cleanText($(contentSelector).first().text()); } catch {}
    }

    return {
        host,
        titleMatches,
        contentMatches,
        paragraphCount: pCount,
        titlePreview: titleText.substring(0, 120),
        contentPreview: bodyPreview.substring(0, 120),
    };
}

import type { BatchItem, BatchStatus } from '../types.ts';
import * as extractor from './extractor.ts';
import * as storage from './storage.ts';
import * as talevox from './exporters/talevoxExporter.ts';
import { normalizeHost } from './domain.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';
import { Buffer } from 'buffer';

let queue: BatchItem[] = [];
let isProcessing = false;
let activeWorkers = 0;
let shouldStop = false;

// Token bucket for rate limiting
let tokens = 0;
let lastRefill = Date.now();

export function getStatus(): BatchStatus {
    const completed = queue.filter(i => i.status === 'success').length;
    const failed = queue.filter(i => i.status === 'failed').length;
    return {
        queue,
        isProcessing,
        completedCount: completed,
        failedCount: failed,
        totalCount: queue.length
    };
}

export function addItems(urls: string[], seriesTitle?: string, startIndex?: number) {
    let currentIndex = startIndex || 1;

    const newItems = urls.map(url => {
        const item: BatchItem = {
            id: Math.random().toString(36).substring(2, 9),
            url: url.trim(),
            status: 'pending' as const,
        };

        // If manual config provided, assign it to the item
        if (seriesTitle) item.manualSeriesTitle = seriesTitle;
        if (startIndex !== undefined) {
            item.manualChapterIndex = currentIndex;
            currentIndex++;
        }

        return item;
    });
    queue.push(...newItems);
}

export function clearQueue() {
    if (!isProcessing) {
        queue = [];
    }
}

export function retryFailed() {
    if (isProcessing) return;
    queue.forEach(item => {
        if (item.status === 'failed') {
            item.status = 'pending';
            item.error = undefined;
            item.result = undefined;
        }
    });
}

export async function startProcessing() {
    if (isProcessing) return;
    shouldStop = false;
    isProcessing = true;

    const settings = await storage.getSettings();
    const maxConcurrency = settings.concurrency || 1;

    // Init tokens
    tokens = settings.rateLimitPerMinute; 
    lastRefill = Date.now();

    // Main loop
    while (!shouldStop) {
        // Refill tokens
        const now = Date.now();
        const elapsed = now - lastRefill;
        if (elapsed > 60000) {
            tokens = settings.rateLimitPerMinute;
            lastRefill = now;
        }

        // Check completion
        const pending = queue.find(i => i.status === 'pending');
        if (!pending && activeWorkers === 0) {
            isProcessing = false;
            break;
        }

        // Spawn worker if allowed
        if (pending && activeWorkers < maxConcurrency && tokens > 0) {
            tokens--;
            activeWorkers++;

            // Add a random jitter delay (500ms - 2500ms) to simulate human behavior
            await new Promise(r => setTimeout(r, Math.random() * 2000 + 500));

            processItem(pending).finally(() => {
                activeWorkers--;
            });
        }

        // Wait a bit before next loop tick
        await new Promise(r => setTimeout(r, 200));
    }

    isProcessing = false;
}

export function stopProcessing() {
    shouldStop = true;
}

async function processItem(item: BatchItem) {
    item.status = 'processing';
    try {
        const templates = await storage.getTemplates();
        const result = await extractor.extract(item.url, templates);
        item.result = result;
        item.status = 'success';
    } catch (e: any) {
        item.status = 'failed';
        item.error = e.message;
        console.error(`Failed ${item.url}:`, e);
    }
}

function deriveTitleFromUrl(url: string): string {
    try {
        const u = new URL(url);
        const segments = u.pathname.split('/').filter(s => s);
        if (segments.length === 0) return '';

        // Take last segment
        let slug = segments[segments.length - 1];

        // Remove known numeric prefixes from slug.
        // Matches patterns like "123-title", "7-1-title", "vol-1-ch-2-title" (simplified as numbers)
        // Regex explanation: ^(?:\d+[-_])+ matches "7-1-" or "123-" or "7-1-2-" at start
        slug = slug.replace(/^(?:\d+[-_])+/, '');

        // Replace dashes/underscores with spaces
        let title = slug.replace(/[-_]/g, ' ');

        // Capitalize Words
        title = title.replace(/\b\w/g, c => c.toUpperCase());

        return title.trim();
    } catch (e) {
        return '';
    }
}

export async function createBatchZip(format: string = 'talevox') {
    const zip = new AdmZip();

    // FILTER AND SORT
    // Sort by manualChapterIndex if available, otherwise fallback to array order (implied by just queue order, but we should be explicit)
    const successItems = queue
        .filter(i => i.status === 'success' && i.result)
        .sort((a, b) => {
             // If both have manual index, sort by that
             if (a.manualChapterIndex && b.manualChapterIndex) {
                 return a.manualChapterIndex - b.manualChapterIndex;
             }
             // Otherwise preserve queue order (by index in the queue array)
             return queue.indexOf(a) - queue.indexOf(b);
        });

    if (format === 'talevox') {
        // TaleVox Export Logic

        // 1. Determine Series Slug
        let seriesSlug = 'series';
        let seriesTitle = 'Unknown Series';

        if (successItems.length > 0) {
            if (successItems[0].manualSeriesTitle) {
                seriesTitle = successItems[0].manualSeriesTitle;
                // Create slug from manual title
                seriesSlug = seriesTitle.toLowerCase().trim()
                    .replace(/\s+/g, '_')
                    .replace(/[^a-z0-9_\-]/g, '');
            } else {
                const host = normalizeHost(successItems[0].url);
                seriesSlug = host.replace(/\./g, '_');
                seriesTitle = seriesSlug;
            }
        }

        const manifestItems: Array<{index: number, title: string, filename: string, url: string}> = [];
        const usedFilenames = new Set<string>();
        let lastAutoIndex = 0;

        successItems.forEach((item, idx) => {
            if (!item.result) return;

            // Resolve Index
            let index = 0;
            if (item.manualChapterIndex !== undefined) {
                index = item.manualChapterIndex;
            } else {
                 const meta = talevox.parseChapterMetadata(item.result.title);
                 if (meta.index !== null) index = meta.index;
                 else index = lastAutoIndex + 1;
            }
            lastAutoIndex = index;

            // Resolve Clean Title
            const meta = talevox.parseChapterMetadata(item.result.title);
            let finalTitle = meta.title;

            // FALLBACK: If title is empty (H1 was just "Chapter X" or "7-1"), try URL slug
            if (!finalTitle && item.url) {
                const slugTitle = deriveTitleFromUrl(item.url);
                // Simple heuristic: If slugTitle is long enough, use it
                if (slugTitle.length > 2) {
                    finalTitle = slugTitle;
                }
            }

            // Auto-detect extension
            const ext = item.result.hasRichContent ? '.md' : '.txt';

            // Generate filename
            let filename = talevox.buildFilename(seriesSlug, index, finalTitle).replace('.txt', ext);

            // Handle duplicates
            let version = 2;
            while(usedFilenames.has(filename)) {
                filename = filename.replace(ext, `__v${version}${ext}`);
                version++;
            }
            usedFilenames.add(filename);

            // Generate Content
            const content = talevox.formatChapterContent(index, finalTitle, item.result.content);

            zip.addFile(filename, Buffer.from(content, 'utf8'));

            manifestItems.push({
                index,
                title: finalTitle || `Chapter ${index}`, 
                filename,
                url: item.url
            });
        });

        const manifestJson = talevox.generateManifest(seriesTitle, seriesSlug, manifestItems);
        zip.addFile('talevox_manifest.json', Buffer.from(manifestJson, 'utf8'));

    } else {
        // Generic Export Logic
        successItems.forEach(item => {
            if (item.result) {
                const ext = item.result.hasRichContent ? '.md' : '.txt';
                const safeTitle = sanitize(item.result.title).substring(0, 100);
                const content = `${item.result.title}\n\n${item.result.content}`;
                zip.addFile(`${safeTitle}${ext}`, Buffer.from(content, 'utf8'));
            }
        });

        // Generic manifest
        const manifest = {
            generatedAt: new Date().toISOString(),
            total: successItems.length,
            items: successItems.map(i => {
                const ext = i.result?.hasRichContent ? '.md' : '.txt';
                return {
                    url: i.url,
                    title: i.result?.title,
                    filename: `${sanitize(i.result?.title || '')}${ext}`
                };
            })
        };
        zip.addFile('manifest.json', Buffer.from(JSON.stringify(manifest, null, 2), 'utf8'));
    }

    return zip.toBuffer();
}

import { ExtractedChapter } from '../../types.ts';

interface TaleVoxOptions {
    seriesSlug: string;
    chapterIndex: number;
    title: string;
    content: string;
    url: string;
}

/**
 * Normalizes text according to TaleVox requirements:
 * - CRLF -> LF
 * - NBSP -> Space
 * - Remove Zero-width chars
 * - Trim lines
 * - Max 2 consecutive newlines
 */
export function cleanText(text: string): string {
    if (!text) return '';

    return text
        // Normalize newlines
        .replace(/\r\n/g, '\n')
        .replace(/\r/g, '\n')
        // Replace non-breaking spaces
        .replace(/\u00A0/g, ' ')
        // Remove zero-width characters (ZWSP, BOM, etc)
        .replace(/[\u200B-\u200D\uFEFF]/g, '')
        // Trim each line
        .split('\n')
        .map(line => line.trim())
        .join('\n')
        // Ensure no more than 2 consecutive newlines (paragraph breaks)
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

/**
 * Parses the raw title to extract the chapter index and the clean descriptive title.
 * e.g. "Book 1: Chapter 3: Castaway" -> { index: 3, title: "Castaway" }
 */
export function parseChapterMetadata(rawTitle: string): { index: number | null, title: string } {
    if (!rawTitle) return { index: null, title: '' };

    let clean = rawTitle;
    let index: number | null = null;

    // 1. Extract Chapter Number
    // Matches "Chapter 123", "Ch 123", "Ch. 123", "Episode 123", "Ep 123"
    // Supports decimals e.g. "Chapter 7.1" or hyphenated "7-1"
    const numMatch = clean.match(/(?:chapter|ch\.?|episode|ep\.?)\s*(\d+(?:[\.\-]\d+)?)/i);
    if (numMatch) {
        index = parseFloat(numMatch[1]);
        index = Math.floor(index);
    }

    // 2. Specialized Cleaning for "Prefix - Chapter X - Title" format (Patreon style)
    // If we find "Chapter X" sandwiched by hyphens, we assume everything before is series junk, and everything after is title.
    const aggressiveSplit = clean.match(/.*(?:chapter|ch\.?|episode|ep\.?)\s*\d+(?:[\.\-]\d+)?\s*[:\-\u2013\u2014|]\s*(.*)$/i);
    if (aggressiveSplit && aggressiveSplit[1]) {
        // We found a specific "Chapter X - [Title]" pattern.
        clean = aggressiveSplit[1].trim();
    } else {
        // Fallback: Standard cleaning

        // Remove "Book X" / "Vol X" patterns
        clean = clean.replace(/(?:book|volume|vol\.?)\s*\d+(?:[\.\-]\d+)?\s*[:\-\u2013\u2014|]?\s*/gi, '');

        // Remove "Chapter X" patterns
        // Expanded separators: Colon (:), Hyphen (-), En-dash (\u2013), Em-dash (\u2014), Pipe (|), Dot (.)
        clean = clean.replace(/(?:chapter|ch\.?|episode|ep\.?)\s*\d+(?:[\.\-]\d+)?\s*[:\-\u2013\u2014|.]?\s*/gi, '');

        // Remove standalone leading numeric patterns that look like "7-1" or "7.1"
        clean = clean.replace(/^\d+(?:[\.\-]\d+)+\s*[:\-\u2013\u2014|.]?\s*/, '');

        // Remove leading separators often left behind (e.g. ": Castaway" or "- Castaway")
        clean = clean.replace(/^[:\-\u2013\u2014\s|.]+/, '').trim();
    }

    return { index, title: clean };
}

/**
 * Formats the file content:
 * Chapter {index}: {CleanTitle}
 * (blank line)
 * [CHAPTER BODY TEXT]
 */
export function formatChapterContent(index: number, title: string, content: string): string {
    let header = `Chapter ${index}`;
    if (title) {
        header += `: ${title}`;
    }

    const body = cleanText(content);
    return `${header}\n\n${body}`;
}

/**
 * Generates filename: {seriesSlug}__{chapterIndexPadded}__{safeTitle}.txt
 * safeTitle: lowercase, spaces->underscores, strict punctuation removal
 */
export function buildFilename(seriesSlug: string, index: number, title: string): string {
    const paddedIndex = index.toString().padStart(4, '0');

    // safeTitle logic: lowercase, max 60 chars
    let safeTitle = title.toLowerCase().trim();
    // Replace spaces with underscores
    safeTitle = safeTitle.replace(/\s+/g, '_');
    // Remove all characters except alphanumeric, underscores, and dashes
    safeTitle = safeTitle.replace(/[^a-z0-9_\-]/g, '');
    // Truncate
    safeTitle = safeTitle.substring(0, 60);
    // Remove trailing underscores/dashes if truncation cut weirdly
    safeTitle = safeTitle.replace(/[_\-]+$/, '');

    // Fallback if title becomes empty (e.g. was just "Chapter 3" and got stripped)
    if (!safeTitle) safeTitle = 'chapter';

    return `${seriesSlug}__${paddedIndex}__${safeTitle}.txt`;
}

export function generateManifest(seriesTitle: string, seriesSlug: string, items: Array<{index: number, title: string, filename: string, url: string}>) {
    return JSON.stringify({
        seriesTitle: seriesTitle, 
        seriesSlug: seriesSlug,
        createdAt: new Date().toISOString(),
        exporter: "RoninClip v2.0",
        chapters: items.map(item => ({
            chapterIndex: item.index,
            title: item.title,
            filename: item.filename,
            sourceUrl: item.url
        }))
    }, null, 2);
}

